var item = $input.first().json;
var body = item.body || item;
var agentName = body.agent_name || 'mlops';
var message = body.message || '';
var sessionId = body.session_id || '';
var explicitSP = body.system_prompt || '';
var explicitTask = body.task || '';
var reqCfg = body.config || {};
if (body.provider) reqCfg.provider = body.provider;
if (body.model) reqCfg.model = body.model;
if (body.temperature != null) reqCfg.temperature = Number(body.temperature);
if (body.mcp_tools) reqCfg.mcp_tools = body.mcp_tools;
var MLFLOW = ($env.MLFLOW_TRACKING_URI || 'http://genai-mlflow.genai.svc.cluster.local') + '/api/2.0/mlflow';
var N8N = $env.N8N_INTERNAL_URL || 'http://genai-n8n.genai.svc.cluster.local:5678/webhook';
var INF_BASE = $env.INFERENCE_BASE_URL || 'http://genai-litellm.genai.svc.cluster.local:4000/v1';
var INF_KEY = $env.LITELLM_API_KEY || '';
var defs = {provider:'ollama',model:'',temperature:0.3,top_p:0.9,num_ctx:32768,max_iterations:10,mcp_tools:''};
return [{json:{
  S:{agent_name:agentName, message:message, session_id:sessionId, explicit_sp:explicitSP, explicit_task:explicitTask, req_cfg:reqCfg, vars:body.variables||{}},
  U:{mlflow:MLFLOW, n8n:N8N, inf_base:INF_BASE, inf_key:INF_KEY},
  R:{system_prompt:'', config:defs, task:'', prompt_versions:{}, skills:[], history:[], tasks:[], task_descs:{}, error:null},
  _skip_mlflow: explicitSP ? true : false,
  _get_system_url: MLFLOW + '/registered-models/get?name=' + encodeURIComponent(agentName + '.SYSTEM')
}}];

var d = $input.first().json;
d.R.system_prompt = d.S.explicit_sp;
d.R.task = d.S.explicit_task;
d.R.config = Object.assign({}, d.R.config, d.S.req_cfg);
return [{json: d}];

var prev = $('Has Explicit Prompt?').first().json;
var resp = $input.first().json;
var model = resp.registered_model;
function pt(a){var m={};if(!a)return m;for(var i=0;i<a.length;i++)m[a[i].key]=a[i].value;return m;}
if (!model) { prev.R.error = 'Agent not found: '+prev.S.agent_name+'.SYSTEM'; return [{json:prev}]; }
var mt = pt(model.tags);
var storedCfg = {}; try{storedCfg=JSON.parse(mt['agent.config']||'{}')}catch(e){}
prev.R.config = Object.assign({}, prev.R.config, storedCfg);
// Get latest version template
var lv = model.latest_versions || [];
var aliases = model.aliases || [];
var targetVer = null;
for (var i=0;i<aliases.length;i++){if(aliases[i].alias==='production'){targetVer=aliases[i].version;break;}}
if (!targetVer && lv.length > 0) {
  var ver = lv[lv.length-1];
  var vt = pt(ver.tags);
  prev.R.system_prompt = vt['mlflow.prompt.text'] || '';
  prev.R.prompt_versions.system = ver.version;
} else if (targetVer) {
  // Need to fetch specific version — store URL for next step
  prev._fetch_version_url = prev.U.mlflow + '/model-versions/get?name=' + encodeURIComponent(prev.S.agent_name+'.SYSTEM') + '&version=' + targetVer;
} else {
  prev.R.error = 'No versions for '+prev.S.agent_name+'.SYSTEM';
}
prev._model_tags = mt;
return [{json:prev}];

var prev = $('Parse System').first().json;
var resp = $input.first().json;
var ver = resp.model_version;
function pt(a){var m={};if(!a)return m;for(var i=0;i<a.length;i++)m[a[i].key]=a[i].value;return m;}
if (ver) {
  var vt = pt(ver.tags);
  prev.R.system_prompt = vt['mlflow.prompt.text'] || '';
  prev.R.prompt_versions.system = ver.version;
}
delete prev._fetch_version_url;
return [{json:prev}];

var prev;
try { prev = $('Parse Version').first().json; } catch(e) {}
if (!prev) { try { prev = $('Parse System').first().json; } catch(e) {} }
if (!prev) return [{json:{R:{error:'internal: lost state'}}}];
if (prev.R.error) return [{json:prev}];
var resp = $input.first().json;
var models = resp.registered_models || [];
function pt(a){var m={};if(!a)return m;for(var i=0;i<a.length;i++)m[a[i].key]=a[i].value;return m;}
var an = prev.S.agent_name, sk = an+'.SYSTEM';
for(var i=0;i<models.length;i++){var n=models[i].name||'';if(n!==sk){var t=n.substring(an.length+1);prev.R.tasks.push(t);var tags=pt(models[i].tags);if(tags['task.description'])prev.R.task_descs[t]=tags['task.description'];}}
if(prev.R.tasks.length>0){prev.R.system_prompt+='\n\nYou can perform these tasks:\n';for(var j=0;j<prev.R.tasks.length;j++){prev.R.system_prompt+='- '+prev.R.tasks[j]+(prev.R.task_descs[prev.R.tasks[j]]?': '+prev.R.task_descs[prev.R.tasks[j]]:'')+'\n';}}
return [{json:prev}];

var prev = $('Has Session?').first().json;
var resp = $input.first().json;
prev.R.history = resp.messages || [];
return [{json:prev}];

var d = $input.first().json;
if (d.R && d.R.error) return [{json:{_error:true, agent_name:d.S.agent_name, error:d.R.error, message:d.S.message, session_id:d.S.session_id}}];
var combined = d.R.system_prompt || '';
if (d.R.task_prompt) combined = combined ? combined+'\n\n'+d.R.task_prompt : d.R.task_prompt;
var config = Object.assign({}, d.R.config, d.S.req_cfg||{});
var vars = d.S.vars || {};
if (!vars.message) vars.message = d.S.message;
for (var key in vars) { combined = combined.replace(new RegExp('\\{\\{\\s*'+key+'\\s*\\}\\}','g'), String(vars[key])); }
return [{json:{_error:false, agent_name:d.S.agent_name, task:d.R.task||undefined, system_prompt:combined, message:d.S.message, session_id:d.S.session_id, messages_history:d.R.history||[], config:config, prompt_versions:d.R.prompt_versions||{}, skills_loaded:d.R.skills&&d.R.skills.length>0?d.R.skills:undefined}}];
